import React, { useState } from 'react';
import Taskcard from './Taskcard';

const Tasks = () => {

  return (
    <div className="task-page">
      <div className="task-input-row">
        <input
          type="text"
          value={taskInput}
          onChange={(e) => setTaskInput(e.target.value)}
          placeholder="Add Task ...."
          className="task-input"
        />
        <button onClick={addTask} className="add-btn">Add</button>
      </div>
      {tasks.map(task => (<Taskcard />))}
      <Stylesheet />
    </div>
  );
};

const Stylesheet = () => (
  <style>{`
    .task-page {
      padding: 2rem;
      font-family: 'Cedarville Cursive', cursive;
      
    }

    .task-input-row {
      display: flex;
      justify-content: center;
      gap: 1rem;
      margin-bottom: 2rem;
    }

    .task-input {
      background-color: var(--secondary-color);  
      border: none;
      padding: 1rem 1.5rem;
      font-size: 1.3rem;
      border-radius: 10px;
      width: 300px;
      font-family: 'Cedarville Cursive', cursive;
    }

    .add-btn {
      padding: 0.8rem 1.5rem;
      background-color: var(--button-color);
      color: var(--bg-parchment);
      border-radius: 10px;
      font-size: 1.2rem;
      cursor: pointer;
      border: none;
      font-family: 'Cedarville Cursive', cursive;
    }

    .task-cards {
      display: flex;
      justify-content: space-evenly;
      flex-wrap: wrap;
      gap: 2rem;
      margin-left:10%;
      margin-right:10%;
    }

    .task-card {
      background-color: var(--secondary-color);
      border: 2px solid var(--button-border);
      padding: 1rem;
      border-radius: 12px;
      width: 220px;
    }

    .task-header {
      display: flex;
      justify-content: space-between;
      align-items: center;
    }

    .task-title {
      font-size: 1.2rem;
      font-weight: bold;
      color: var(--text);
    }

    .task-title-input {
      background-color: var(--flower-white);
      border: 1px solid var(--button-border);
      border-radius: 5px;
      font-size: 1rem;
      padding: 0.3rem;
      width: 80%;
      font-family: 'Cedarville Cursive', cursive;
    }

    .icons {
      display: flex;
    }

    .icons button {
      background: none;
      border: none;
      font-size: 1.1rem;
      margin-left: 5px;
      cursor: pointer;
    }

    .icon {
      height: 25px;
    }

    .task-items {
      margin-top: 1rem;
      list-style: none;
      padding: 0;
    }

    .task-items li {
      display: flex;
      align-items: center;
      gap: 0.5rem;
      margin: 0.3rem 0;
    }

    .subtask-input {
      flex: 1;
      background: transparent;
      border: none;
      font-size: 0.9rem;
      font-family: 'Cedarville Cursive', cursive;
    }

    .subtask-input:focus {
      outline: none;
    }

    .checked {
      text-decoration: line-through;
    }
  `}</style>
);

export default Tasks;
